@ExtendWith(MockitoExtension.class)
class LoanApplicationServiceImplTest {

    @Mock
    private LoanApplicationRepository loanApplicationRepository;

    @InjectMocks
    private LoanApplicationServiceImpl service;

    // Helper: build a minimal LoanApplication entity
    private LoanApplication buildApplication(Long id, Long applicantUserId) {
        LoanApplication app = new LoanApplication();
        app.setApplicationId(id);
        app.setApplicantUserId(applicantUserId);
        app.setStatus(LoanApplicationStatus.SUBMITTED);
        app.setLoanType(com.loanflow.loanservice.entity.LoanType.PERSONAL);
        app.setRequestedAmount(BigDecimal.valueOf(25000));
        app.setTermMonths(48);
        app.setAnnualIncome(BigDecimal.valueOf(92000));
        app.setSubmittedAt(LocalDateTime.now());
        return app;
    }

    @Test
    void getApplicationById_throwsResourceNotFound_whenApplicationDoesNotExist() {
        when(loanApplicationRepository.findById(99L)).thenReturn(Optional.empty());
        assertThatThrownBy(() -> service.getApplicationById(99L, 1L, "APPLICANT"))
            .isInstanceOf(ResourceNotFoundException.class)
            .hasMessageContaining("99");
    }

    @Test
    void getApplicationById_throwsAccessDenied_whenApplicantRequestsOtherUsersApplication() {
        when(loanApplicationRepository.findById(1L)).thenReturn(Optional.of(buildApplication(1L, 10L)));
        assertThatThrownBy(() -> service.getApplicationById(1L, 99L, "APPLICANT"))
            .isInstanceOf(AccessDeniedException.class);
    }

    @Test
    void getApplicationById_returnsResponse_forOwningApplicant() {
        when(loanApplicationRepository.findById(1L)).thenReturn(Optional.of(buildApplication(1L, 10L)));
        ApplicationDetailResponse response = service.getApplicationById(1L, 10L, "APPLICANT");
        assertThat(response.getApplicationId()).isEqualTo(1L);
        assertThat(response.getStatus()).isEqualTo(LoanStatus.SUBMITTED);
    }

    @Test
    void getApplicationById_returnsResponse_forLoanOfficerRegardlessOfOwnership() {
        when(loanApplicationRepository.findById(1L)).thenReturn(Optional.of(buildApplication(1L, 10L)));
        ApplicationDetailResponse response = service.getApplicationById(1L, 99L, "LOAN_OFFICER");
        assertThat(response.getApplicationId()).isEqualTo(1L);
    }
}
