@WebMvcTest(LoanApplicationController.class)
@Import(SecurityConfig.class)
class LoanApplicationControllerTest {

    @Autowired
    private MockMvc mockMvc;

    @MockBean
    private LoanApplicationService loanApplicationService;

    @Autowired
    private ObjectMapper objectMapper;

    // POST — no JWT → 401
    @Test
    void createApplication_noJwt_returns401() throws Exception {
        mockMvc.perform(post("/api/v1/applications")
                .contentType(MediaType.APPLICATION_JSON)
                .content(objectMapper.writeValueAsString(validRequest())))
            .andExpect(status().isUnauthorized());
    }

    // POST — LOAN_OFFICER role → 403
    @Test
    void createApplication_loanOfficerRole_returns403() throws Exception {
        mockMvc.perform(post("/api/v1/applications")
                .with(jwt().authorities(new SimpleGrantedAuthority("ROLE_LOAN_OFFICER")))
                .contentType(MediaType.APPLICATION_JSON)
                .content(objectMapper.writeValueAsString(validRequest())))
            .andExpect(status().isForbidden());
    }

    // POST — null loanType → 400
    @Test
    void createApplication_nullLoanType_returns400() throws Exception {
        CreateLoanApplicationRequest badRequest = CreateLoanApplicationRequest.builder()
            .loanType(null)
            .amount(BigDecimal.valueOf(25000))
            // ... other required fields
            .build();
        mockMvc.perform(post("/api/v1/applications")
                .with(jwt().authorities(new SimpleGrantedAuthority("ROLE_APPLICANT")).claim("userId", 1L).claim("roles", List.of("APPLICANT")))
                .contentType(MediaType.APPLICATION_JSON)
                .content(objectMapper.writeValueAsString(badRequest)))
            .andExpect(status().isBadRequest())
            .andExpect(jsonPath("$.status").value(400));
    }

    // GET — APPLICANT owner → 200
    @Test
    void getApplicationById_owningApplicant_returns200() throws Exception {
        when(loanApplicationService.getApplicationById(50021L, 10L, "APPLICANT"))
            .thenReturn(ApplicationDetailResponse.builder().applicationId(50021L).build());

        mockMvc.perform(get("/api/v1/applications/50021")
                .with(jwt().claim("userId", 10L).claim("roles", List.of("APPLICANT"))))
            .andExpect(status().isOk())
            .andExpect(jsonPath("$.applicationId").value(50021));
    }

    private CreateLoanApplicationRequest validRequest() {
        return CreateLoanApplicationRequest.builder()
            .loanType(LoanType.PERSONAL)
            .amount(BigDecimal.valueOf(25000))
            .termMonths(48)
            .annualIncome(BigDecimal.valueOf(92000))
            .employmentStatus(EmploymentStatus.FULL_TIME)
            .applicantDetails(ApplicantDetailsRequest.builder()
                .firstName("Devin").lastName("Catuns")
                .email("devin@example.com").phone("555-0147")
                .build())
            .build();
    }
}
