@DataJpaTest
@ActiveProfiles("test")
class LoanApplicationRepositoryTest {

    @Autowired
    private LoanApplicationRepository repository;

    @Autowired
    private TestEntityManager entityManager;

    private LoanApplication persist(Long userId, LoanApplicationStatus status, LoanType loanType) {
        LoanApplication app = new LoanApplication();
        app.setApplicantUserId(userId);
        app.setApplicationReference(UUID.randomUUID().toString());
        app.setStatus(status);
        app.setLoanType(loanType);
        app.setRequestedAmount(BigDecimal.valueOf(25000));
        app.setTermMonths(48);
        app.setAnnualIncome(BigDecimal.valueOf(92000));
        app.setEmploymentStatus(EmploymentStatus.FULL_TIME);
        return entityManager.persistAndFlush(app);
    }

    @Test
    void findByApplicationReference_returnsEmpty_forUnknownReference() {
        assertThat(repository.findByApplicationReference("unknown-ref")).isEmpty();
    }

    @Test
    void findByApplicantUserId_returnsOnlyMatchingUser() {
        persist(10L, LoanApplicationStatus.SUBMITTED, LoanType.PERSONAL);
        persist(10L, LoanApplicationStatus.SUBMITTED, LoanType.AUTO);
        persist(99L, LoanApplicationStatus.SUBMITTED, LoanType.PERSONAL);
        assertThat(repository.findByApplicantUserId(10L)).hasSize(2);
    }

    @Test
    void existsByApplicantUserIdAndLoanTypeAndStatusIn_returnsTrue_forActiveApplication() {
        persist(10L, LoanApplicationStatus.SUBMITTED, LoanType.PERSONAL);
        boolean exists = repository.existsByApplicantUserIdAndLoanTypeAndStatusIn(
            10L, LoanType.PERSONAL, List.of(LoanApplicationStatus.SUBMITTED));
        assertThat(exists).isTrue();
    }

    @Test
    void existsByApplicantUserIdAndLoanTypeAndStatusIn_returnsFalse_whenNoneMatch() {
        boolean exists = repository.existsByApplicantUserIdAndLoanTypeAndStatusIn(
            10L, LoanType.PERSONAL, List.of(LoanApplicationStatus.SUBMITTED));
        assertThat(exists).isFalse();
    }
}
