@SpringBootTest(webEnvironment = SpringBootTest.WebEnvironment.RANDOM_PORT)
@ActiveProfiles("test")
class LoanServiceIntegrationTest {

    @Autowired
    private TestRestTemplate restTemplate;

    private HttpHeaders applicantHeaders() {
        String token = JwtTestHelper.generateToken(10L, "APPLICANT");
        HttpHeaders headers = new HttpHeaders();
        headers.setBearerAuth(token);
        headers.setContentType(MediaType.APPLICATION_JSON);
        return headers;
    }

    @Test
    void createAndRetrieveApplication_fullFlow() {
        CreateLoanApplicationRequest request = /* valid request */ ...;

        // POST → 201
        ResponseEntity<CreateLoanApplicationResponse> createResp = restTemplate.exchange(
            "/api/v1/applications",
            HttpMethod.POST,
            new HttpEntity<>(request, applicantHeaders()),
            CreateLoanApplicationResponse.class);
        assertThat(createResp.getStatusCode()).isEqualTo(HttpStatus.CREATED);
        Long appId = createResp.getBody().getApplicationId();

        // GET → 200
        ResponseEntity<ApplicationDetailResponse> getResp = restTemplate.exchange(
            "/api/v1/applications/" + appId,
            HttpMethod.GET,
            new HttpEntity<>(applicantHeaders()),
            ApplicationDetailResponse.class);
        assertThat(getResp.getStatusCode()).isEqualTo(HttpStatus.OK);
        assertThat(getResp.getBody().getApplicationId()).isEqualTo(appId);
    }

    @Test
    void getApplication_unknownId_returns404() {
        ResponseEntity<String> resp = restTemplate.exchange(
            "/api/v1/applications/99999",
            HttpMethod.GET,
            new HttpEntity<>(applicantHeaders()),
            String.class);
        assertThat(resp.getStatusCode()).isEqualTo(HttpStatus.NOT_FOUND);
    }
}
